#include <bits/stdc++.h>
using namespace std;
const int maxn=3e6+5;
int a[maxn],f[maxn];
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n;
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	stack<int> sta;
	for(int i=1;i<=n;i++){
		while(!sta.empty()&&a[i]>a[sta.top()]){
			f[sta.top()]=i;
			sta.pop();
		}
		sta.push(i);
	}
	for(int i=1;i<=n;i++){
		cout<<f[i]<<" ";
	}
	return 0;
}
